def copy_configs(inputs: DeploymentInputs) -> None:
    files = [
        "config-deploy-l1.toml",
        "config-deploy-l2-config.toml"
    ]

    for f in files:
        run_command(
            "Copy config files",
            f"cp deploy-script-config-template/{f} script-config",
            inputs.l1_contracts_dir,
            inputs.base_env(),
    )
    
    # Write register-zk-chain.toml
    with open(f"{inputs.l1_contracts_dir}/script-config/register-zk-chain.toml", "w") as f:
        f.write(register_zk_chain_toml_template)

